SELECT SUM(obs_count) AS total_observations
FROM daily_obs_count
WHERE site_id = 0 AND date = '2020-01-02';

SELECT obs_count
FROM daily_obs_count
WHERE site_id = 1 AND date = '2020-01-01';

SELECT SUM(obs_count) AS total_observations
FROM daily_obs_count
WHERE site_id = 1 AND date >= '2020-01-01' AND date <= '2020-01-31';

SELECT AVG(percent_complete) AS average_percent_complete
FROM percent_complete
WHERE site_id = 1 AND date = '2020-01-02';

SELECT site_id, percent_complete
FROM percent_complete
WHERE date = '2020-01-01';

SELECT site_id
FROM monitoring_equipment
WHERE calibration_date >= DATE('now', '-1 year');

SELECT AVG(value) AS average_pollutant_concentration
FROM data
WHERE site_id = 0 AND pollutant_id = 1;
